```class Solution {
    public String strWithout3a3b(int a, int b) {
        StringBuilder sb = new StringBuilder();
        while (a > 0 || b > 0) {
            if (a > 1 && b > 0) {
                sb.append("aa");
                a -= 2;
                sb.append("b");
                b--;
            } else if (a > 0) {
                sb.append("a");
                a--;
            } else if (b > 1) {
                sb.append("b");
                b -= 2;
            } else {
                sb.append("b");
                b--;
            }
        }
        return sb.toString();
    }
}```
